function itemBasePremiums(items: Item[]): number[] {
  // For main items, base premium is straightforward.
  // For components, group by type and apply block discount.
  const result: number[] = new Array(items.length).fill(0);

  // collect indices grouped by component type
  const componentIndicesByType: Record<string, number[]> = {};

  for (let i = 0; i < items.length; i++) {
    const item = items[i];
    if (isMainItem(item.type)) {
      result[i] = MAIN_ITEMS[item.type].premium;
    } else if (isComponent(item.type)) {
      if (!componentIndicesByType[item.type]) componentIndicesByType[item.type] = [];
      componentIndicesByType[item.type].push(i);
    }
  }

  for (const type of Object.keys(componentIndicesByType)) {
    const indices = componentIndicesByType[type];
    const count = indices.length;
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const remainder = count % COMPONENT_BLOCK_SIZE;
    // Distribute premium equally as fractions across the indices? The base premium is
    // attributable to components as a group. To keep per-item base premium for surcharges,
    // we'll just allocate evenly so that item-specific surcharges can use per-item base.
    // But components don't have cursed/enchantment so we can keep a group total.
    // For simplicity, since the item-level surcharges only matter for main items
    // (components have no enchantment/cursed in spec), distribute evenly.
    const groupTotal = blocks * COMPONENT_BLOCK_PREMIUM + remainder * COMPONENT_PREMIUM;
    const perItem = groupTotal / count;
    for (const idx of indices) {
      result[idx] = perItem;
    }
  }

  return result;
}

function itemSurcharge(item: Item, basePremium: number): number {
  let surcharge = 0;
  if (item.cursed) surcharge += basePremium * 0.5;
  if (typeof item.enchantment === "number" && item.enchantment >= 5) surcharge += basePremium * 0.3;
  return surcharge;
}

export interface QuoteContext {
  yearsWithMHPCO: number;
  isFollowUpContract: boolean; // true when this quote is not the customer's first
}

function roundUp(value: number): number {
  // round up to whole G (favor MHPCO for premiums)
  return Math.ceil(value - 1e-9);
}

function roundDown(value: number): number {
  // round down to whole G (favor MHPCO for payouts)
  return Math.floor(value + 1e-9);
}

export function computePremium(items: Item[], context: QuoteContext): number {
  validateItems(items);

  const basePremiums = itemBasePremiums(items);
  const policyBase = basePremiums.reduce((a, b) => a + b, 0);

  // Item-level surcharges
  let itemSurcharges = 0;
  for (let i = 0; i < items.length; i++) {
    itemSurcharges += itemSurcharge(items[i], basePremiums[i]);
  }

  // Policy-wide modifiers apply to the policy base premium
  let policyModifiers = 0;
  if (context.yearsWithMHPCO >= 2) policyModifiers -= policyBase * 0.2; // loyalty discount
  // First insurance surcharge - 10 % per item (each item treated as first insurance)
  // Per spec: "each item in a `quote` is treated as a first insurance"
  // Apply 10% surcharge to each item's base premium.
  let firstInsuranceSurcharge = 0;
  for (let i = 0; i < items.length; i++) {
    firstInsuranceSurcharge += basePremiums[i] * 0.1;
  }

  if (context.isFollowUpContract) policyModifiers -= policyBase * 0.15;

  const subtotal = policyBase + itemSurcharges + policyModifiers + firstInsuranceSurcharge;
  const withFee = subtotal + PROCESSING_FEE;

  return roundUp(withFee);
}

export interface PolicyState {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

export function createPolicy(items: Item[]): PolicyState {
  validateItems(items);
  const insuranceSum = policyInsuranceSum(items);
  const cap = insuranceSum * 2;
  return { items, insuranceSum, cap, remainingCap: cap };
}

function isDragonMaterial(item: Item): boolean {
  return item.material === "dragon";
}

function isHighlyEnchanted(item: Item): boolean {
  return typeof item.enchantment === "number" && item.enchantment >= 8;
}

export function processClaim(policy: PolicyState, incident: Incident): ClaimResult {
  // Validate damages: each damage must correspond to an item in the policy.
  // Multiple entries of the same type require sufficient covered items.
  const itemsByType: Record<string, Item[]> = {};
  for (const it of policy.items) {
    if (!itemsByType[it.type]) itemsByType[it.type] = [];
    itemsByType[it.type].push(it);
  }

  // Validate negative amounts and unknown types
  for (const d of incident.damages) {
    if (d.amount < 0) {
      throw new Error(`Negative damage amount not allowed: ${d.amount}`);
    }
    if (!isMainItem(d.itemType) && !isComponent(d.itemType)) {
      throw new Error(`Unknown damage item type: ${d.itemType}`);
    }
  }

  // Pair damages with items, consuming each item once.
  const consumed: Record<string, number> = {};
  const pairings: { item: Item; amount: number }[] = [];
  for (const d of incident.damages) {
    const list = itemsByType[d.itemType] || [];
    const used = consumed[d.itemType] || 0;
    if (used >= list.length) {
      throw new Error(`Damage refers to item not in policy: ${d.itemType}`);
    }
    pairings.push({ item: list[used], amount: d.amount });
    consumed[d.itemType] = used + 1;
  }

  let totalPayout = 0;
  for (const { item, amount } of pairings) {
    let damage = amount;
    // Dragon material wins over enchantment 50% clause
    if (isDragonMaterial(item)) {
      // full reimbursement
      damage = amount;
    } else if (isHighlyEnchanted(item)) {
      damage = amount * 0.5;
    }
    const afterDeductible = Math.max(0, damage - DEDUCTIBLE);
    totalPayout += afterDeductible;
  }

  const rounded = roundDown(totalPayout);
  const capped = Math.min(rounded, policy.remainingCap);
  policy.remainingCap -= capped;
  return { payout: capped, remainingCap: policy.remainingCap };
}

export function runScenario(scenario: Scenario): ScenarioOutput {
  const results: StepResult[] = [];
  const policies: Record<number, PolicyState> = {};
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      const isFollowUp = quoteCount > 0;
      const premium = computePremium(step.items, {
        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
        isFollowUpContract: isFollowUp,
      });
      results.push({ premium });
      policies[i] = createPolicy(step.items);
      quoteCount++;
    } else if (step.op === "claim") {
      const policy = policies[step.policy];
      if (!policy) {
        throw new Error(`Claim references unknown policy index: ${step.policy}`);
      }
      const result = processClaim(policy, step.incident);
      results.push(result);
    } else {
      throw new Error(`Unknown operation`);
    }
  }

  return { results };
}

