  it("steel sword, ench 9, damage 1000 → 400 (50% then deductible)", () => {
    const out = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 9 }] },
